logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers, topic_name, group_id=None,
                 auto_offset_reset='latest', enable_auto_commit=True,
                 value_deserializer=lambda m: json.loads(m.decode('utf-8'))):
        """
        Initializes the Kafka consumer for financial transactions.

        Args:
            bootstrap_servers (str or list): List of Kafka broker addresses.
            topic_name (str or list): The topic(s) to subscribe to.
            group_id (str, optional): The consumer group ID. If None, it's an independent consumer.
            auto_offset_reset (str): 'earliest' or 'latest'. Determines where to start consuming.
            enable_auto_commit (bool): If True, offsets are periodically committed in the background.
            value_deserializer (callable): Function to deserialize message values.
                                            Defaults to JSON deserializer.
        """
        self.topic_name = topic_name
        self.group_id = group_id
        self.consumer = KafkaConsumer(
            bootstrap_servers=bootstrap_servers,
            group_id=group_id,
            auto_offset_reset=auto_offset_reset,
            enable_auto_commit=enable_auto_commit,
            value_deserializer=value_deserializer,
            key_deserializer=lambda k: k.decode('utf-8') if k else None,
            api_version=(0, 10),  # Recommended for modern Kafka brokers
        )
        self.message_handlers = {}
        logging.info(f"Kafka Consumer initialized for topics: {topic_name}, group_id: {group_id}")

    def register_handler(self, transaction_type, handler_func):
        """
        Registers a handler function for a specific transaction type.

        Args:
            transaction_type (str): The type of transaction (e.g., 'DEPOSIT', 'WITHDRAWAL').
            handler_func (callable): The function to execute when a transaction of this type is received.
                                     It should accept one argument: the deserialized transaction data.
        """
        if not callable(handler_func):
            raise ValueError("Handler must be a callable function.")
        self.message_handlers[transaction_type.upper()] = handler_func
        logging.info(f"Registered handler for transaction type: {transaction_type.upper()}")

    def _default_handler(self, transaction_data):
        """
        Default handler for transaction types without a specific registered handler.
        """
        transaction_type = transaction_data.get('transaction_type', 'UNKNOWN').upper()
        logging.warning(f"No specific handler registered for transaction type '{transaction_type}'. "
                        f"Processing with default logic for transaction ID: {transaction_data.get('transaction_id')}")
        # Example default logic: just log the data
        print(f"Default processing for: {transaction_data}")

    def process_message(self, message):
        """
        Processes a single Kafka message, deserializing its value and
        dispatching it to the appropriate handler.
        """
        try:
            transaction_data = message.value
            transaction_type = transaction_data.get('transaction_type')

            if not transaction_type:
                logging.error(f"Message {message.offset} from {message.topic} has no 'transaction_type'. Skipping.")
                return

            handler = self.message_handlers.get(transaction_type.upper(), self._default_handler)

            logging.info(f"Processing transaction ID: {transaction_data.get('transaction_id')}, "
                         f"Type: {transaction_type}, Topic: {message.topic}, Offset: {message.offset}")

            handler(transaction_data)

        except json.JSONDecodeError as e:
            logging.error(f"JSON decoding error for message at offset {message.offset} in topic {message.topic}: {e}. Raw value: {message.value}")
        except Exception as e:
            logging.error(f"Error processing message at offset {message.offset} in topic {message.topic}: {e}", exc_info=True)

    def start_consuming(self):
        """
        Starts the Kafka consumer loop to continuously poll for new messages.
        """
        try:
            # If group_id is provided, subscribe to topics
            if self.group_id:
                self.consumer.subscribe(self.topic_name if isinstance(self.topic_name, list) else [self.topic_name])
                logging.info(f"Consumer subscribed to topics: {self.consumer.subscription()}")
            else:
                # If no group_id, assign to specific partitions for independent consumption
                # This requires 'topic_name' to be a string representing a single topic
                if not isinstance(self.topic_name, str):
                    raise ValueError("When group_id is None, topic_name must be a single string.")
                partitions = self.consumer.partitions_for_topic(self.topic_name)
                if not partitions:
                    raise Exception(f"No partitions found for topic: {self.topic_name}. Is the topic created?")
                tp = [TopicPartition(self.topic_name, p) for p in partitions]
                self.consumer.assign(tp)
                logging.info(f"Consumer assigned to partitions: {tp}")

            logging.info("Starting Kafka consumer loop...")
            while True:
                messages = self.consumer.poll(timeout_ms=1000) # Poll for messages, with a 1-second timeout
                if messages:
                    for tp, records in messages.items():
                        for record in records:
                            self.process_message(record)
                    if not self.consumer.config['enable_auto_commit']:
                        self.consumer.commit() # Manual commit if auto_commit is disabled
                else:
                    logging.debug("No messages received within the poll timeout.")

        except KeyboardInterrupt:
            logging.info("Consumer stopped by user (KeyboardInterrupt).")
        except Exception as e:
            logging.critical(f"Unhandled exception in consumer loop: {e}", exc_info=True)
        finally:
            self.consumer.close()
            logging.info("Kafka Consumer closed.")

